                                    {story.audioSrc && (
                                        <audio controls src={story.audioSrc} className="w-full h-8 mt-2" />
                                    )}
                                </div>
                            ))}
                        </div>
                    </div>
                )}
            </div>
        </div>
      </div>
    </div>
  );
};

