const compressImage = async (file: File): Promise<Blob> => {
  return new Promise((resolve, reject) => {
    const img = new Image();
    const url = URL.createObjectURL(file);
    img.onload = () => {
      URL.revokeObjectURL(url);
      let width = img.width;
      let height = img.height;
      if (width > height) {
        if (width > MAX_IMAGE_DIMENSION) {
          height = Math.round((height * MAX_IMAGE_DIMENSION) / width);
          width = MAX_IMAGE_DIMENSION;
        }
      } else if (height > MAX_IMAGE_DIMENSION) {
        width = Math.round((width * MAX_IMAGE_DIMENSION) / height);
        height = MAX_IMAGE_DIMENSION;
      }
      const canvas = document.createElement('canvas');
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext('2d');
      if (!ctx) return reject(new Error('Canvas context fail'));
      ctx.drawImage(img, 0, 0, width, height);
      canvas.toBlob((blob) => {
        if (blob) resolve(blob);
        else reject(new Error('Compression failed'));
      }, 'image/jpeg', IMAGE_QUALITY);
    };
    img.onerror = (err) => {
      URL.revokeObjectURL(url);
      reject(err);
    };
    img.src = url;
  });
};

const App: React.FC = () => {
  const [photos, setPhotos] = useState<Photo[]>([]);
  const [stories, setStories] = useState<Story[]>([]);
  const [appState, setAppState] = useState<'upload' | 'ready' | 'unpacked' | 'slideshowSetup' | 'slideshow'>('upload');
  const [selectedPhoto, setSelectedPhoto] = useState<Photo | null>(null);
  const [isWelcomeDismissed, setIsWelcomeDismissed] = useState(false);
  const [isCoverLifting, setIsCoverLifting] = useState(false);
  const createdUrlsRef = useRef<Set<string>>(new Set());
  const [isIdle, setIsIdle] = useState(false);
  const idleTimerRef = useRef<number | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const [familyNames, setFamilyNames] = useState<Map<string, Set<string>>>(new Map());
  const [keywordTags, setKeywordTags] = useState<Set<string>>(new Set());

  const [activeFilter, setActiveFilter] = useState<FilterState | null>(null);
  const [focusedPhotoId, setFocusedPhotoId] = useState<number | null>(null);

  const [showStoryLinker, setShowStoryLinker] = useState(false);
  const [filesForLinker, setFilesForLinker] = useState<File[]>([]);
  const [initialManifestForLinker, setInitialManifestForLinker] = useState<any[]>([]);

  const [slideshowConfig, setSlideshowConfig] = useState<SlideshowConfig>({
    includedTags: new Set(), style: 'fade', showCaptions: true, order: 'random', music: 'none', speed: 5000,
  });
  const [slideshowPhotos, setSlideshowPhotos] = useState<Photo[]>([]);

  useEffect(() => {
    return () => createdUrlsRef.current.forEach(url => URL.revokeObjectURL(url));
  }, []);

  const resetIdleTimer = useCallback(() => {
    if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
    idleTimerRef.current = window.setTimeout(() => {
      if (photos.length > 0 && appState === 'unpacked' && !activeFilter?.value) setIsIdle(true);
    }, IDLE_TIMEOUT);
  }, [photos.length, appState, activeFilter]);

  useEffect(() => {
    if (appState === 'unpacked') {
      const handleActivity = () => resetIdleTimer();
      resetIdleTimer();
      window.addEventListener('mousemove', handleActivity, { passive: true });
      window.addEventListener('mousedown', handleActivity, { passive: true });
      window.addEventListener('touchstart', handleActivity, { passive: true });
      return () => {
        if (idleTimerRef.current) clearTimeout(idleTimerRef.current);
        window.removeEventListener('mousemove', handleActivity);
      };
    }
  }, [appState, resetIdleTimer]);

  const processFiles = useCallback(async (filesToProcess: File[], storyManifest?: any[]) => {
    setIsProcessing(true);
    const filesArray = Array.from(filesToProcess);
    const imageFiles = filesArray.filter(f => f.type.startsWith('image/'));
    const storyManifestFile = filesArray.find(f => f.name.toLowerCase() === 'stories.json');
    const textFiles = new Map(filesArray.filter(f => f.type === 'text/plain').map(f => [f.name, f]));
    const audioFiles = new Map(filesArray.filter(f => f.type.startsWith('audio/')).map(f => [f.name, f]));

    let photosForProcessing = [...photos];
    let storiesForProcessing = [...stories];
    const startingIndex = photosForProcessing.length;

    const newPhotosData: (Photo | null)[] = [];
    const BATCH_SIZE = 5;

    for (let i = 0; i < imageFiles.length; i += BATCH_SIZE) {
      const batch = imageFiles.slice(i, i + BATCH_SIZE);
      const batchResults = await Promise.all(batch.map(async (file, idx) => {
        const globalIdx = startingIndex + i + idx;
        let metadata = { title: '', caption: '', people: '', location: '', copyright: '', keywords: [] as string[], exifData: {} as Record<string, any> };
        let photoDate = file.lastModified;

        try {
          const parsedMeta = await exifr.parse(file, { tiff: true, xmp: true, iptc: true, ifd0: true, mergeOutput: false, reviveValues: true });
          const repairText = (s: string) => s ? s.replace(/Ã©/g, 'é').replace(/Ã¨/g, 'è').replace(/M©tis/g, 'Métis').replace(/\0/g, '').trim() : '';
          const extractText = (val: any): string => {
            if (!val) return '';
            if (val instanceof Uint8Array) return repairText(new TextDecoder().decode(val));
            if (typeof val === 'string') return repairText(val);
            if (Array.isArray(val)) return val.map(v => extractText(v)).filter(Boolean).join(', ');
            if (typeof val === 'object') return extractText(val.value || val['x-default'] || Object.values(val)[0]);
            return String(val).trim();
          };

          const titleCandidates = [parsedMeta.xmp?.['dc:title'], parsedMeta.xmp?.title, parsedMeta.iptc?.Headline, parsedMeta.ifd0?.XPTitle];
          for (const c of titleCandidates) {
            const t = extractText(c);
            if (t && t.toLowerCase() !== 'default') { metadata.title = t; break; }
          }
          if (!metadata.title) {
            let n = file.name.substring(0, file.name.lastIndexOf('.')).replace(/[-_]/g, ' ');
            metadata.title = /^(IMG|DSC|PXL|MVI|VID)_\d+$/i.test(n) ? file.name : n;
          }

          const capCandidates = [parsedMeta.xmp?.['dc:description'], parsedMeta.iptc?.['Caption-Abstract'], parsedMeta.ifd0?.ImageDescription, parsedMeta.exif?.UserComment];
          for (const c of capCandidates) {
            const t = extractText(c);
            if (t && t !== metadata.title) { metadata.caption = t; break; }
          }

          const copyCandidates = [parsedMeta.xmp?.['dc:rights'], parsedMeta.iptc?.CopyrightNotice, parsedMeta.exif?.Copyright];
          for (const c of copyCandidates) {
            const t = extractText(c);
            if (t) { metadata.copyright = t; break; }
          }

          const kwSet = new Set<string>();
          const addKw = (src: any) => {
            if (!src) return;
            if (typeof src === 'string') src.split(/[;,|>]/).forEach(k => k.trim() && kwSet.add(repairText(k)));
            else if (Array.isArray(src)) src.forEach(addKw);
            else if (typeof src === 'object') Object.values(src).forEach(addKw);
          };
          addKw(parsedMeta.xmp?.subject); addKw(parsedMeta.iptc?.keywords);
          metadata.keywords = Array.from(kwSet).filter(k => k !== file.name);

          const city = extractText(parsedMeta.iptc?.City);
          const country = extractText(parsedMeta.iptc?.['Country-Primary-Location-Name']);
          metadata.location = [city, country].filter(Boolean).join(', ');

          const flatExif = { ...parsedMeta.tiff, ...parsedMeta.exif, ...parsedMeta.ifd0 };
          metadata.exifData = { 'Camera': extractText(flatExif.Model), 'ISO': flatExif.ISO, 'Aperture': flatExif.FNumber ? `f/${flatExif.FNumber}` : undefined };
          if (parsedMeta.exif?.DateTimeOriginal instanceof Date) photoDate = parsedMeta.exif.DateTimeOriginal.getTime();
        } catch (e) { console.warn("Meta error", e); }

        try {
          const blob = await compressImage(file);
          const src = URL.createObjectURL(blob);
          createdUrlsRef.current.add(src);
          return {
            id: Date.now() + globalIdx, src, alt: file.name, ...metadata,
            position: { x: window.innerWidth * 0.1 + Math.random() * (window.innerWidth * 0.7), y: window.innerHeight * 0.1 + Math.random() * (window.innerHeight * 0.6) },
            rotation: Math.random() * 50 - 25, initialRotation: 0, zIndex: globalIdx, isPinned: false, scale: 1, initialScale: 1, lastModified: photoDate,
            animationDelay: globalIdx * 50, animationDuration: 800 + Math.random() * 500, fontClass: FONT_CLASSES[Math.floor(Math.random() * FONT_CLASSES.length)],
          } as Photo;
        } catch (e) { return null; }
      }));
      newPhotosData.push(...batchResults);
    }

    const storyPromise = storyManifest ? Promise.resolve(storyManifest) : (storyManifestFile ? storyManifestFile.text().then(JSON.parse) : Promise.resolve([]));
    const finalManifest = await storyPromise;
    const validNewPhotos = newPhotosData.filter((p): p is Photo => p !== null);
    let updatedPhotos = [...photosForProcessing, ...validNewPhotos];

    // ... (rest of story linking logic remains the same)
    setPhotos(updatedPhotos);
    setIsProcessing(false);
    if (appState === 'upload') setAppState('ready');
  }, [photos, stories, appState]);

  const handleFileUpload = (uploadedFiles: FileList) => {
    if (isProcessing) return;
    const files = Array.from(uploadedFiles);
    processFiles(files);
  };

  const handleShuffle = () => {
    setPhotos(curr => curr.map(p => ({
      ...p,
      position: { x: window.innerWidth * 0.1 + Math.random() * (window.innerWidth * 0.7), y: window.innerHeight * 0.1 + Math.random() * (window.innerHeight * 0.6) },
      rotation: p.isPinned ? 0 : (Math.random() * 50 - 25),
    })));
  };

  const handleReset = () => { setAppState('ready'); setIsCoverLifting(false); setActiveFilter(null); };
  const handleUnpack = () => { setIsCoverLifting(true); setTimeout(() => setAppState('unpacked'), 800); };
  const handlePhotoClick = useCallback((p: Photo) => setSelectedPhoto(p), []);
  const handleFocusPhoto = useCallback((id: number) => setFocusedPhotoId(id), []);

  const { matchingPhotos, nonMatchingPhotos } = useMemo(() => {
    if (!activeFilter) return { matchingPhotos: [], nonMatchingPhotos: photos };
    const matching: Photo[] = [];
    const nonMatching: Photo[] = [];
    photos.forEach(p => {
      let match = false;
      if (activeFilter.type === 'keyword') match = (p.keywords || []).some(k => k.toLowerCase().includes(activeFilter.value.toLowerCase()));
      else if (activeFilter.type === 'family') match = p.people?.toLowerCase().includes(activeFilter.value.toLowerCase()) || false;
      if (match) matching.push(p); else nonMatching.push(p);
    });
    return { matchingPhotos: matching, nonMatchingPhotos: nonMatching };
  }, [photos, activeFilter]);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-black">
      {isProcessing && (
        <div className="absolute inset-0 z-[10000] bg-black/80 flex flex-col items-center justify-center text-white">
          <div className="w-12 h-12 border-4 border-red-600 border-t-transparent rounded-full animate-spin mb-4"></div>
          <p className="text-xl font-heading tracking-widest uppercase">Processing & Optimizing...</p>
        </div>
      )}
      {isIdle ? <Screensaver photos={photos} onWakeUp={() => setIsIdle(false)} /> : (
        <>
          {appState === 'upload' && <UploadScreen onUpload={handleFileUpload} />}
          {appState === 'ready' && <ShoeboxCover onUnpack={handleUnpack} isLifting={isCoverLifting} onEnterSlideshowSetup={() => setAppState('slideshowSetup')} />}
          {appState === 'unpacked' && (
            <div className="absolute inset-0">
              {photos.map((p) => (
                <PhotoItem 
                  key={p.id} photo={p} onUpdate={(id, u) => setPhotos(curr => curr.map(ph => ph.id === id ? {...ph, ...u} : ph))}
                  onBringToFront={(id) => setPhotos(curr => { const maxZ = Math.max(...curr.map(x => x.zIndex)); return curr.map(x => x.id === id ? {...x, zIndex: maxZ + 1} : x); })}
                  onPhotoClick={handlePhotoClick} onFocusPhoto={handleFocusPhoto} isUnpacked={true}
                  isFilterActive={!!activeFilter} isMatch={matchingPhotos.some(m => m.id === p.id)} isFocused={p.id === focusedPhotoId}
                  matchIndex={matchingPhotos.findIndex(m => m.id === p.id)} totalMatches={matchingPhotos.length}
                  focusedPhotoIndex={matchingPhotos.findIndex(m => m.id === focusedPhotoId)}
                  nonMatchIndex={nonMatchingPhotos.findIndex(m => m.id === p.id)} totalNonMatches={nonMatchingPhotos.length}
                />
              ))}
            </div>
          )}
          {appState === 'unpacked' && (
            <div className="absolute top-4 right-4 z-[9999] flex gap-2">
              <button onClick={handleShuffle} className="bg-white/90 px-4 py-2 rounded shadow font-bold text-red-800 uppercase text-xs">Shuffle</button>
              <button onClick={handleReset} className="bg-white/90 px-4 py-2 rounded shadow font-bold text-red-800 uppercase text-xs">Repack</button>
            </div>
          )}
          {activeFilter && <FilterNotification activeFilter={activeFilter} onClear={() => setActiveFilter(null)} />}
          {selectedPhoto && <PhotoDetailModal photo={selectedPhoto} stories={[]} onClose={() => setSelectedPhoto(null)} />}
        </>
      )}
    </div>
  );
};
