import React, { useState, useEffect, useRef } from 'react';
import type { Photo } from '../types';
import { PinIcon } from './Icons';

const PHOTO_ITEM_WIDTH = 240;

const PhotoItem: React.FC<any> = React.memo(({ 
  photo, onUpdate, onBringToFront, onPhotoClick, onFocusPhoto, 
  isUnpacked, isFilterActive, isMatch, isFocused, matchIndex, focusedPhotoIndex, nonMatchIndex, totalNonMatches 
}) => {
  const nodeRef = useRef<HTMLDivElement>(null);
  const [isRendered, setIsRendered] = useState(false);

  useEffect(() => {
    const t = setTimeout(() => setIsRendered(true), 50);
    return () => clearTimeout(t);
  }, []);

  let currentStyles: React.CSSProperties = {};
  if (isFilterActive) {
    if (isMatch) {
      if (isFocused) {
        currentStyles = { left: '50%', top: '50%', transform: 'translate(-50%, -50%) rotate(0deg) scale(1.5)', opacity: 1, zIndex: 5000 };
      } else {
        const offset = matchIndex - focusedPhotoIndex;
        const x = (window.innerWidth / 2) - (PHOTO_ITEM_WIDTH / 2) + (Math.sign(offset) * (Math.abs(offset) * 60 + 150));
        const y = (window.innerHeight / 2) - 150 + (Math.abs(offset) * 20);
        currentStyles = { transform: `translate3d(${x}px, ${y}px, 0) rotate(${offset * 5}deg) scale(0.8)`, opacity: 0.8, zIndex: 1000 - Math.abs(offset) };
      }
    } else {
      const x = (window.innerWidth / 2) + (nonMatchIndex - totalNonMatches / 2) * 20;
      currentStyles = { transform: `translate3d(${x}px, ${window.innerHeight - 80}px, 0) scale(0.2)`, opacity: 0.2, zIndex: 1 };
    }
  } else {
    currentStyles = isRendered && isUnpacked ? {
      transform: `translate3d(${photo.position.x}px, ${photo.position.y}px, 0) rotate(${photo.rotation}deg) scale(${photo.scale})`,
      opacity: 1, zIndex: photo.zIndex
    } : { transform: 'translate3d(50vw, 50vh, 0) scale(0)', opacity: 0 };
  }

  // SNAPPY UNIFORM TRANSITION FOR FILTERS
  const transitionTime = isFilterActive ? '500ms' : `${photo.animationDuration}ms`;
  const transitionDelay = isFilterActive ? '0ms' : `${photo.animationDelay}ms`;

  return (
    <div
      ref={nodeRef}
      className="absolute bg-white shadow-sharp p-3 flex flex-col cursor-pointer transition-all ease-in-out"
      style={{
        ...currentStyles, width: PHOTO_ITEM_WIDTH,
        transitionDuration: isRendered ? transitionTime : '0ms',
        transitionDelay: isRendered ? transitionDelay : '0ms',
        willChange: 'transform, opacity'
      }}
      onClick={() => isFocused || !isFilterActive ? onPhotoClick(photo) : onFocusPhoto(photo.id)}
      onMouseDown={() => onBringToFront(photo.id)}
    >
      <div className="w-full bg-gray-100 overflow-hidden">
        <img src={photo.src} alt={photo.alt} loading="lazy" decoding="async" className="w-full h-auto block" />
      </div>
      <div className="mt-3 min-h-[40px] flex items-center justify-center">
        <p className={`${photo.fontClass} text-gray-800 text-center font-bold text-sm truncate px-1`}>
          {photo.title || "Untitled"}
        </p>
      </div>
    </div>
  );
});
export default PhotoItem;

